generated_oml:
// Sensing Components
instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Sensor that measures the current I_M of the permanent‑magnet synchronous motor"
    DTDFVocab:producedData CurrentDataStream
]

instance MotorAngleSensor : DTDFVocab:SensingComponent [
    base:desc "Motor encoder that reports the angular position of the motor shaft"
    DTDFVocab:producedData MotorAngleDataStream
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder mounted behind the drive gearbox\\nthat measures the output angular position"
    DTDFVocab:producedData GearboxAngleDataStream
]

// Data Transmitted
instance CurrentDataStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance MotorAngleDataStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorAngleSensor
]

instance GearboxAngleDataStream : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoderSensor
]

// Measurement Data
instance CurrentData : DTDFVocab:Data [
    base:desc "Array of floating‑point measurements of the motor current I_M"
    DTDFVocab:fromData CurrentDataStream
    DTDFVocab:inputTo MQTTBroker_RTTI
]

instance MotorAngleData : DTDFVocab:Data [
    base:desc "Array of floating‑point values of motor shaft angular position (rad)"
    DTDFVocab:fromData MotorAngleDataStream
    DTDFVocab:inputTo MQTTBroker_RTTI
]

instance GearboxAngleData : DTDFVocab:Data [
    base:desc "Array of floating‑point values of gearbox output angular position (rad)"
    DTDFVocab:fromData GearboxAngleDataStream
    DTDFVocab:inputTo MQTTBroker_RTTI
]

// Enablers
instance SysMLTool_v17 : DTDFVocab:Enabler [
    base:desc "SysML version 1.7 tool used for Model‑Based Systems Engineering of the robot axis"
    DTDFVocab:enables SysMLModelingService
]

instance MATLABSimulinkTool : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink platform used to run executable simulation models of the motor and gearboxes"
    DTDFVocab:enables SimulinkSimulationService
]

instance MQTTBroker_RTTI : DTDFVocab:Enabler [
    base:desc "MQTT broker that streams real‑time data from the physical twin to the digital twin"
    DTDFVocab:enables MQTTStreamingService
]

instance AssetAdministrationShell : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell that provides a semantic, machine‑readable description of the robot axis assets"
    DTDFVocab:enables AssetAdhShellService
]

instance WebDashboard_App : DTDFVocab:Enabler [
    base:desc "Web‑based dashboard that visualizes measured versus simulated data traces and generates actionable insights"
    DTDFVocab:enables UnifiedDashboardService
]

// Services
instance UnifiedDashboardService : DTDFVocab:Service [
    base:desc "Unified dashboard service that visualizes real‑time joint friction diagnostics and provides insights and actions for maintenance and control"
    DTDFVocab:provides FrictionLossInsight, FrictionCalibrationDeviationInsight
    DTDFVocab:provides UpdateRobotControlAlgorithmAction, ScheduleMaintenanceAction
]

instance SimulinkSimulationService : DTDFVocab:Service [
    base:desc "Service that executes Simulink models of motor, gearbox, and friction dynamics"
    DTDFVocab:provides SimulatedTorqueInsight, SimulatedVelocityInsight
]

instance MQTTStreamingService : DTDFVocab:Service [
    base:desc "Service that forwards streamed sensor data through MQTT to downstream consumers"
]

instance SysMLModelingService : DTDFVocab:Service [
    base:desc "Service that manages SysML‑based component and connector models"
]

instance AssetAdhShellService : DTDFVocab:Service [
    base:desc "Service that exposes the Asset Administration Shell for asset discovery and integration"
]

// Insights
instance FrictionLossInsight : DTDFVocab:Insight [
    base:desc "Insight identifying measurable friction loss in the robot joint from discrepancies between measured and simulated torque"
]

instance FrictionCalibrationDeviationInsight : DTDFVocab:Insight [
    base:desc "Insight that highlights when friction calibration diverges beyond predefined thresholds, triggering maintenance actions"
]

instance SimulatedTorqueInsight : DTDFVocab:Insight [
    base:desc "Insight representing simulated torque from Simulink models"
]

instance SimulatedVelocityInsight : DTDFVocab:Insight [
    base:desc "Insight representing simulated angular velocity from Simulink models"
]

// Actions
instance UpdateRobotControlAlgorithmAction : DTDFVocab:Action [
    base:desc "Automatic action that updates the robot control algorithm parameters based on updated friction estimates"
    DTDFVocab:IsAutomatic true
]

instance ScheduleMaintenanceAction : DTDFVocab:Action [
    base:desc "Automatic action that schedules maintenance for the joint when calibration deviations exceed thresholds"
    DTDFVocab:IsAutomatic true
]

// Data Models
instance MotorDriverSim : DTDFVocab:Model [
    base:desc "Simulink model of the synchronous motor driver dynamics"
    DTDFVocab:inputTo MATLABSimulinkTool
]

instance MotorWheelSim : DTDFVocab:Model [
    base:desc "Simulink model of the motor cogwheel interaction"
    DTDFVocab:inputTo MATLABSimulinkTool
]

instance DriveGearboxSim : DTDFVocab:Model [
    base:desc "Simulink model of the primary gear gearbox connecting motor to joint"
    DTDFVocab:inputTo MATLABSimulinkTool
]

instance FrictionSim_CoulombViscous : DTDFVocab:Model [
    base:desc "Simulink model representing Coulomb plus viscous friction law for the joint"
    DTDFVocab:inputTo MATLABSimulinkTool
]

instance FrictionSim_Stribeck : DTDFVocab:Model [
    base:desc "Simulink model implementing Stribeck friction for the joint"
    DTDFVocab:inputTo MATLABSimulinkTool
]

instance FrictionSim_Dahl : DTDFVocab:Model [
    base:desc "Simulink model using Dahl friction for dynamic backlash representation"
    DTDFVocab:inputTo MATLABSimulinkTool
]

instance FrictionSim_LuGre : DTDFVocab:Model [
    base:desc "Simulink model of the LuGre friction dynamics"
    DTDFVocab:inputTo MATLABSimulinkTool
]

// Environment and Components
instance DigitalTwinEnvironment : DTDFVocab:Environment [
    base:contains RobotAxisComponent, MotorComponent, DriveGearboxComponent, CycloidalGearboxComponent
]

instance RobotAxisComponent : DTDFVocab:Component [
    base:desc "First axis of the industrial robot MABI MAX 100, comprising motor, drive gearbox, and cycloidal gearbox"
]

instance MotorComponent : DTDFVocab:Component [
    base:desc "Permanent‑magnet synchronous motor driving the first joint"
]

instance DriveGearboxComponent : DTDFVocab:Component [
    base:desc "Drive gearbox (gearwheel) that transmits torque from the motor to the cycloidal gearbox"
]

instance CycloidalGearboxComponent : DTDFVocab:Component [
    base:desc "Cycloidal gearbox that converts rotary motion to precise linear motion for the joint"
]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Continuous real‑time operation; data streams are sampled at the sensor’s native rate (motor current and encoder signals) and processed immediately by the DT’s simulation and model‑calibration components."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "The DT constellation orchestrates sensor data ingestion via MQTT, AAS‑mediated asset description, a processing component that consumes data traces and executes simulation models, and an abstraction layer that delivers aggregated traces to the visualization dashboard. The whole system is rooted in the Digital Shadow Reference Model, instantiated specifically for the MABI MAX‑100 first axis."
]

instance life_cycle_stages : DTDFVocab:EvolutionStage [
    base:desc "The twin is developed through a purpose‑driven methodology that covers a design phase (model creation in SysML and Simulink) and an operated phase (live data capture and continuous friction‑model updating). It explicitly covers the operating condition of the robot, rather than the manufactured or design phase."
]

instance fidelity_and_validity_considerations : DTDFVocab:FidelityConsideration [
    base:desc "Model fidelity is ensured through continuous traceability from data to model, with comparisons between measured and simulated traces. Validation is performed by residual analysis of torque and angular‑velocity deviations. Uncertainty arises from sensor noise, model parameter variability, and wear; these are mitigated via online calibration of both white‑box (analytical) and black‑box (data‑driven) friction models."
]

instance dt_technical_connection : DTDFVocab:TechnicalConnection [
    base:desc "The PT communicates with the DT via MQTT, a lightweight publish/subscribe protocol over TCP/IP. Asset Administration Shells (AAS) provide semantic metadata about each data source (e.g., encoder channels, current sensor). The DT processes data in real time and stores traces in a local database or time‑series store."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The approach employs established standards: SysML for modeling, AAS per Industrie 4.0 for asset description, and ISO/IEC 2382‑1 terminology for Digital Twins. The methodology follows MBSE best practices and Industry‑4.0 ontologies."
]
